import { createClient, isSupabaseConfigured } from './supabase/server';

export type SiteSettingKey =
  | 'testimonials'
  | 'snow_removal'
  | 'nav_services'
  | 'nav_about'
  | 'spring_banner';

export const SITE_SETTING_LABELS: Record<SiteSettingKey, string> = {
  testimonials: 'Testimonials (home page)',
  snow_removal: 'Snow removal CTA & service card',
  nav_services: 'Services nav link',
  nav_about: 'About nav link',
  spring_banner: 'Spring spots banner (home hero)',
};

export async function getSiteSettings(): Promise<Record<SiteSettingKey, boolean>> {
  const defaults: Record<SiteSettingKey, boolean> = {
    testimonials: true,
    snow_removal: true,
    nav_services: true,
    nav_about: true,
    spring_banner: true,
  };

  if (!isSupabaseConfigured()) return defaults;

  const supabase = await createClient();
  const { data } = await supabase.from('site_settings').select('key, enabled');
  if (!data) return defaults;

  const result = { ...defaults };
  for (const row of data) {
    if (row.key in result) {
      result[row.key as SiteSettingKey] = !!row.enabled;
    }
  }
  return result;
}

export async function updateSiteSetting(
  key: SiteSettingKey,
  enabled: boolean
): Promise<void> {
  if (!isSupabaseConfigured()) {
    throw new Error('Supabase not configured');
  }
  const supabase = await createClient();
  await supabase
    .from('site_settings')
    .upsert({ key, enabled, updated_at: new Date().toISOString() });
}
