import { NextRequest, NextResponse } from 'next/server';
import { getSiteSettings, updateSiteSetting } from '@/lib/site-settings';
import type { SiteSettingKey } from '@/lib/site-settings';

export async function GET() {
  try {
    const settings = await getSiteSettings();
    return NextResponse.json(settings);
  } catch (error) {
    console.error('Error fetching site settings:', error);
    return NextResponse.json(
      {
        testimonials: true,
        snow_removal: true,
        nav_services: true,
        nav_about: true,
        spring_banner: true,
      },
      { status: 200 }
    );
  }
}

export async function PATCH(request: NextRequest) {
  try {
    const body = await request.json();
    const { key, enabled } = body as { key: SiteSettingKey; enabled: boolean };
    const validKeys: SiteSettingKey[] = [
      'testimonials',
      'snow_removal',
      'nav_services',
      'nav_about',
      'spring_banner',
    ];
    if (!validKeys.includes(key) || typeof enabled !== 'boolean') {
      return NextResponse.json(
        { success: false, message: 'Invalid key or enabled value' },
        { status: 400 }
      );
    }
    await updateSiteSetting(key, enabled);
    const settings = await getSiteSettings();
    return NextResponse.json({ success: true, settings });
  } catch (error) {
    console.error('Error updating site setting:', error);
    return NextResponse.json(
      { success: false, message: 'Failed to update setting' },
      { status: 500 }
    );
  }
}
